import{_ as t,c as l,o as i,a5 as r,j as a}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.8：桌面版性能大提升","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.8.md","filePath":"changelog/v1.1.8.md","lastUpdated":1772014034000}'),h={name:"changelog/v1.1.8.md"};function d(n,e,o,s,c,p){return i(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="v1-1-8-桌面版性能大提升" tabindex="-1">v1.1.8：桌面版性能大提升 <a class="header-anchor" href="#v1-1-8-桌面版性能大提升" aria-label="Permalink to “v1.1.8：桌面版性能大提升”">​</a></h1><p><strong>发布日期</strong>：2026年1月9日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新主要是<strong>桌面版性能优化</strong>，长对话不再卡顿，同时新增了多选问答功能。</p><hr><h2 id="新功能-多选问答" tabindex="-1">新功能：多选问答 <a class="header-anchor" href="#新功能-多选问答" aria-label="Permalink to “新功能：多选问答”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>OpenCode 现在支持<strong>多选类型的问答</strong>了。当 AI 需要你做选择时，可以同时选择多个选项。</p><h3 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to “使用场景”">​</a></h3><p>比如 AI 问你「这个重构需要更新哪些文件？」，你可以一次选择多个文件，而不是一个一个选。</p><hr><h2 id="桌面版-性能大幅提升" tabindex="-1">桌面版：性能大幅提升 <a class="header-anchor" href="#桌面版-性能大幅提升" aria-label="Permalink to “桌面版：性能大幅提升”">​</a></h2><p>这次桌面版做了大量性能优化，特别是<strong>长对话场景</strong>：</p><table tabindex="0"><thead><tr><th>优化项</th><th>效果</th></tr></thead><tbody><tr><td>Markdown 缓存</td><td>不再重复渲染已显示的内容</td></tr><tr><td>懒加载 Diff</td><td>代码差异按需加载，不卡顿</td></tr><tr><td>分块加载消息</td><td>长对话滚动更流畅</td></tr><tr><td>预加载相邻会话</td><td>切换会话更快</td></tr></tbody></table><p><strong>简单说</strong>：长对话不再卡了。</p><hr><h2 id="改进-文件自动补全更精准" tabindex="-1">改进：文件自动补全更精准 <a class="header-anchor" href="#改进-文件自动补全更精准" aria-label="Permalink to “改进：文件自动补全更精准”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>在输入框用 <code>@</code> 引用文件时，自动补全只匹配文件名，有时候找不到想要的文件。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>现在使用<strong>完整文件路径</strong>进行模糊匹配，更容易找到目标文件。</p><p>比如输入 <code>@comp/but</code> 可以匹配到 <code>src/components/Button.tsx</code>。</p><hr><h2 id="改进-escape-键不再误触" tabindex="-1">改进：Escape 键不再误触 <a class="header-anchor" href="#改进-escape-键不再误触" aria-label="Permalink to “改进：Escape 键不再误触”">​</a></h2><h3 id="之前的问题-1" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-1" aria-label="Permalink to “之前的问题”">​</a></h3><p>在弹窗（对话框）中按 Escape 键关闭弹窗时，按键事件会「穿透」到主界面，可能触发其他操作。</p><h3 id="现在的情况-1" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-1" aria-label="Permalink to “现在的情况”">​</a></h3><p>Escape 键事件现在会被弹窗正确拦截，不会影响主界面。</p><hr><h2 id="桌面版-项目侧边栏修复" tabindex="-1">桌面版：项目侧边栏修复 <a class="header-anchor" href="#桌面版-项目侧边栏修复" aria-label="Permalink to “桌面版：项目侧边栏修复”">​</a></h2><h3 id="之前的问题-2" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-2" aria-label="Permalink to “之前的问题”">​</a></h3><p>项目侧边栏有时候只显示文件夹名，不显示完整项目名。</p><h3 id="现在的情况-2" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-2" aria-label="Permalink to “现在的情况”">​</a></h3><p>现在正确显示项目名称了。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>使用桌面版</td><td>✅ 强烈推荐升级</td></tr><tr><td>长对话经常卡顿</td><td>✅ 升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',39),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),r('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core-核心" tabindex="-1">Core（核心） <a class="header-anchor" href="#core-核心" aria-label="Permalink to “Core（核心）”">​</a></h3><ul><li>升级 OpenTUI 到 v0.1.70</li><li>支持多选问答</li><li>文档添加 cargofmt 说明（@marc2332）</li></ul><h3 id="tui-终端界面" tabindex="-1">TUI（终端界面） <a class="header-anchor" href="#tui-终端界面" aria-label="Permalink to “TUI（终端界面）”">​</a></h3><ul><li>阻止 Escape 键从弹窗穿透到主界面</li><li>文件自动补全使用完整路径进行模糊匹配（@bagatka）</li></ul><h3 id="desktop-桌面版" tabindex="-1">Desktop（桌面版） <a class="header-anchor" href="#desktop-桌面版" aria-label="Permalink to “Desktop（桌面版）”">​</a></h3><ul><li>回退外部链接在默认浏览器打开的修复</li><li>缓存会话级 store，添加可选的 context gating</li><li>增量渲染消息，Markdown 缓存，懒加载 Diff</li><li>控制 hydration 副作用和 store 加载时机</li><li>预加载相邻会话</li><li>实现分块消息加载和懒加载 Diff，提升性能</li><li>修复项目侧边栏文件夹名显示问题（@0xajka）</li></ul><h3 id="社区贡献" tabindex="-1">社区贡献 <a class="header-anchor" href="#社区贡献" aria-label="Permalink to “社区贡献”">​</a></h3><ul><li>@marc2332：文档添加 cargofmt</li><li>@bagatka：文件自动补全优化</li><li>@0xajka：项目侧边栏修复</li><li>@Anthuang：添加 Vesper 主题</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const f=t(h,[["render",d]]);export{m as __pageData,f as default};
